# similarity: token F1 + LCS-based ratio
def lcs_len(a,b):
    # compute LCS length over characters quickly -> DP O(n*m) could be heavy. We'll approximate with SequenceMatcher ratio?
    # We'll do difflib.SequenceMatcher.ratio as approx
    sm = difflib.SequenceMatcher(None, a, b)
    return sm.ratio()

def token_f1(a,b):
    ta = a.split()
    tb = b.split()
    sa = set(ta)
    sb = set(tb)
    if not sa and not sb:
        return 1.0
    if not sa or not sb:
        return 0.0
    inter = sa & sb
    if not inter:
        return 0.0
    prec = len(inter)/len(sa)
    rec = len(inter)/len(sb)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

